import { Widther } from '@andes/widther';
import warning from '../../utils/warning';
import { WARNING_WIDTHER } from '../../constants/warnings';

/** @type {typeof import('../../..').Widther<any>} */
const WidtherDeprecate = (WrappedComponent) => {
  warning(false, WARNING_WIDTHER);

  return Widther(WrappedComponent);
};

export default WidtherDeprecate;
