import React from 'react';
import PropTypes from 'prop-types';
import { VisuallyHidden } from '@andes/visually-hidden';
import { WARNING_VISUALLY_HIDDEN } from '../../constants/warnings';
import warning from '../../utils/warning';


/** @type {typeof import('../../..').VisuallyHidden} */
const VisuallyHiddenDeprecate = (props) => {
  warning(false, WARNING_VISUALLY_HIDDEN);

  return (
    <VisuallyHidden {...props} />
  );
};

VisuallyHiddenDeprecate.propTypes = {
  children: PropTypes.oneOfType([PropTypes.node, PropTypes.arrayOf(PropTypes.node)]).isRequired,
  component: PropTypes.oneOf(['div', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'span']),
};

export default VisuallyHiddenDeprecate;
