import React from 'react';
import PropTypes from 'prop-types';
import { CloseListener } from '@andes/close-listener';
import warning from '../../utils/warning';
import { WARNING_CLOSE_LISTENER } from '../../constants/warnings';

/** @type {typeof import('../../..').CloseListener} */
const CloseListenerDeprecate = (props) => {
  warning(false, WARNING_CLOSE_LISTENER);

  return <CloseListener {...props} />;
};

CloseListenerDeprecate.propTypes = {
  children: PropTypes.element.isRequired,
  onCloseOutside: PropTypes.func.isRequired,
  handleClick: PropTypes.bool,
  handleEsc: PropTypes.bool,
};

export default CloseListenerDeprecate;
