import React from 'react';
import PropTypes from 'prop-types';
import { VisuallyHiddenFocusable } from '@andes/visually-hidden';
import { WARNING_VISUALLY_HIDDEN_FOCUSABLE } from '../../constants/warnings';
import warning from '../../utils/warning';

/** @type {typeof import('../../..').VisuallyHiddenFocusable} */
const VisuallyHiddenFocusableDeprecate = (props) => {
  warning(false, WARNING_VISUALLY_HIDDEN_FOCUSABLE);

  return (
    <VisuallyHiddenFocusable
      {...props}
    />
  );
};

VisuallyHiddenFocusableDeprecate.propTypes = {
  className: PropTypes.string,
  children: PropTypes.oneOfType([PropTypes.node, PropTypes.arrayOf(PropTypes.node)]),
  component: PropTypes.oneOf(['input', 'textarea', 'button', 'select', 'option', 'a', 'details', 'summary']),
};

export default VisuallyHiddenFocusableDeprecate;
