import React from 'react';
import PropTypes from 'prop-types';
import { Image } from '@andes/image';
import { WARNING_IMAGE } from '../../constants/warnings';
import warning from '../../utils/warning';

/** @type {typeof import('../../..').Image} */
const ImageDeprecate = (props) => {
  warning(false, WARNING_IMAGE);

  return (
    <Image
      {...props}
    />
  );
};

ImageDeprecate.propTypes = {
  title: PropTypes.string,
  src: PropTypes.string,
  src2x: PropTypes.string,
  width: PropTypes.string,
  height: PropTypes.string,
  className: PropTypes.string,
};

export default ImageDeprecate;
